def validate(args, output):
    nums = args[0]
    threshold = args[1]
    n = len(nums)
    # does ANY valid subarray exist?
    # a length-k window starting at i is valid iff min(window) > threshold/k
    # i.e. min(window) * k > threshold
    exists = False
    # O(n^2) reference existence check (fine for validator-sized inputs)
    for i in range(n):
        m = nums[i]
        for j in range(i, n):
            if nums[j] < m:
                m = nums[j]
            k = j - i + 1
            if m * k > threshold:
                exists = True
                break
        if exists:
            break
    if not exists:
        return output == -1
    # output must be a real k for which some window of that length is valid
    if not isinstance(output, int):
        return False
    k = output
    if k < 1 or k > n:
        return False
    for i in range(0, n - k + 1):
        m = min(nums[i:i+k])
        if m * k > threshold:
            return True
    return False

