function validate(args, output) {
    const nums = args[0];
    const threshold = args[1];
    const n = nums.length;
    let exists = false;
    for (let i = 0; i < n && !exists; i++) {
        let m = nums[i];
        for (let j = i; j < n; j++) {
            if (nums[j] < m) m = nums[j];
            const k = j - i + 1;
            if (m * k > threshold) { exists = true; break; }
        }
    }
    if (!exists) return output === -1;
    if (!Number.isInteger(output)) return false;
    const k = output;
    if (k < 1 || k > n) return false;
    for (let i = 0; i + k <= n; i++) {
        let m = Infinity;
        for (let t = i; t < i + k; t++) m = Math.min(m, nums[t]);
        if (m * k > threshold) return true;
    }
    return false;
}

