class Solution:
    def validSubarraySize(self, nums, threshold):
        n = len(nums)
        # brute force: smallest valid k (deterministic) by checking every window
        for k in range(1, n + 1):
            for i in range(0, n - k + 1):
                if min(nums[i:i+k]) * k > threshold:
                    return k
        return -1

