var validSubarraySize = function(nums, threshold) {
    const n = nums.length;
    const prevS = new Array(n).fill(-1);
    const nextS = new Array(n).fill(n);
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && nums[stack[stack.length - 1]] >= nums[i]) stack.pop();
        prevS[i] = stack.length ? stack[stack.length - 1] : -1;
        stack.push(i);
    }
    stack = [];
    for (let i = n - 1; i >= 0; i--) {
        while (stack.length && nums[stack[stack.length - 1]] >= nums[i]) stack.pop();
        nextS[i] = stack.length ? stack[stack.length - 1] : n;
        stack.push(i);
    }
    let anyValid = false;
    for (let i = 0; i < n; i++) {
        const width = nextS[i] - prevS[i] - 1;
        if (nums[i] * width > threshold) { anyValid = true; break; }
    }
    if (!anyValid) return -1;
    for (let k = 1; k <= n; k++) {
        for (let i = 0; i < n; i++) {
            const width = nextS[i] - prevS[i] - 1;
            if (width >= k && nums[i] * k > threshold) return k;
        }
    }
    return -1;
};
